63	
64	<BaseLayout
65	  title={`${post.data.title} - AstroStatic`}
66	  description={post.data.description}
67	  image={ogImageUrl}
68	  imageAlt={post.data.imageAlt}
69	  type="article"
70	  articleMeta={{
71	    publishedTime: post.data.date.toISOString(),
